mapper.select:
select * from orders


        and number like concat('%',#{number},'%')


        and phone like concat('%',#{phone},'%')


        and user_id = #{userId}


        and status = #{status}


        and order_time >= #{beginTime}


        and order_time <= #{endTime}


order by order_time desc

select sum(amount) from orders

    and order_time > #{begin}
    and order_time < #{end}
    and status=#{status}

select count(id) from orders

    and order_time > #{begin}
    and order_time < #{end}
    and status=#{status}

SELECT od.name , sum(od.number) number FROM orders o,order_detail od WHERE o.id=od.order_id and o.status = 5
AND o.order_time > #{begin}
AND o.order_time < #{end}
GROUP BY od.name ORDER BY number DESC LIMIT 10
